-- ----------------------------
DROP TABLE IF EXISTS `member_wx`;
CREATE TABLE `member_wx` (
                             `id` bigint NOT NULL COMMENT 'ID',
                             `member_id` bigint NOT NULL COMMENT '会员ID',
                             `mp_open_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '微信公众号OPENGID',
                             `union_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '微信公众号OPENGID',
                             `mini_app_open_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '小程序OPENGID',
