-- ----------------------------
-- Table structure for order
-- ----------------------------
DROP TABLE IF EXISTS `order`;
CREATE TABLE `order` (
                         `id` bigint NOT NULL COMMENT 'ID',
                         `store_id` bigint NOT NULL COMMENT '店铺ID',
                         `store_name` varchar(32) COLLATE utf8mb4_bin NOT NULL COMMENT '店铺名称',
                         `order_code` varchar(32) COLLATE utf8mb4_bin NOT NULL COMMENT '订单编号',
                         `order_header_code` varchar(32) COLLATE utf8mb4_bin NOT NULL COMMENT '订单头订单编号',
                         `order_time` datetime(6) NOT NULL COMMENT '下单时间',
                         `member_id` bigint NOT NULL COMMENT '会员ID',
                         `product_num` int NOT NULL COMMENT '商品数量',
                         `product_price` decimal(20,2) NOT NULL COMMENT '商品总金额',
                         `coupon_price` decimal(20,2) DEFAULT '0.00' COMMENT '优惠券总金额',
                         `activity_price` decimal(20,2) DEFAULT '0.00' COMMENT '促销活动总金额',
                         `freight_price` decimal(20,2) DEFAULT '0.00' COMMENT '运费总金额',
                         `settlement_price` decimal(20,2) DEFAULT NULL COMMENT '结算金额',
                         `pay_price` decimal(20,2) NOT NULL COMMENT '支付总金额',
                         `order_status` varchar(32) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '订单状态',
                         `pay_status` varchar(32) COLLATE utf8mb4_bin NOT NULL COMMENT '付款状态',
                         `pay_method` varchar(32) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '支付方式',
                         `pay_time` datetime(6) DEFAULT NULL COMMENT '支付时间',
                         `pay_no` varchar(32) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '支付方式返回的交易号',
                         `remark` varchar(256) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '买家订单备注',
                         `receive_name` varchar(32) COLLATE utf8mb4_bin NOT NULL COMMENT '收货人姓名',
                         `receive_mobile` varchar(32) COLLATE utf8mb4_bin NOT NULL COMMENT '手机号码',
                         `receive_path_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '收货地址',
                         `receive_path_id` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '收货地址',
                         `receive_path_detail` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '详细地址',
                         `cancel` int NOT NULL DEFAULT '1' COMMENT '是否可取消 true/false 可以/不可以',
                         `cancel_time` datetime(6) DEFAULT NULL COMMENT '取消时间',
                         `cancel_reason` varchar(64) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '订单取消原因',
                         `create_time` datetime(6) DEFAULT NULL COMMENT '创建时间',
                         `create_by` varchar(32) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '创建者',
                         `update_by` varchar(32) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '修改者',
                         `update_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
                         `delete_flag` int DEFAULT NULL COMMENT '删除标志 true/false 删除/未删除',
                         PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='门店订单表';

-- ----------------------------
-- Records of order
-- ----------------------------
BEGIN;
COMMIT;

