DROP TABLE IF EXISTS `order_log`;
CREATE TABLE `order_log` (
  `id` bigint NOT NULL COMMENT 'ID',
  `order_code` varchar(32) COLLATE utf8mb4_bin NOT NULL COMMENT '订单编号',
  `message` varchar(256) COLLATE utf8mb4_bin NOT NULL COMMENT '日志信息',
  `operator_id` bigint NOT NULL COMMENT '操作者ID',
  `operator_name` varchar(32) COLLATE utf8mb4_bin NOT NULL COMMENT '操作者名称',
  `operator_type` varchar(255) COLLATE utf8mb4_bin NOT NULL COMMENT '操作者类型',
  `create_time` datetime(6) DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(32) COLLATE utf8mb4_bin DEFAULT NULL COMMENT '创建者',
