-- ----------------------------
-- Table structure for product
-- ----------------------------
DROP TABLE IF EXISTS `product`;
CREATE TABLE `product` (
  `id` bigint NOT NULL COMMENT 'ID',
  `product_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '商品名称',
  `product_code` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '商品名称',
  `brand_id` bigint NOT NULL COMMENT '品牌ID',
  `category_class_one` bigint NOT NULL COMMENT '一级商品分类',
  `category_class_two` bigint NOT NULL COMMENT '二级商品分类',
  `category_class_three` bigint NOT NULL COMMENT '三级商品分类',
  `category_class_four` bigint NOT NULL COMMENT '四级商品分类',
  `buy_count` int DEFAULT '0' COMMENT '购买数量',
  `cost_price` decimal(20,2) NOT NULL COMMENT '成本价格',
  `sale_price` decimal(20,2) NOT NULL COMMENT '销售价格',
  `market_price` decimal(20,2) NOT NULL COMMENT '吊牌价格',
  `audit_status` int DEFAULT '0' COMMENT '审核状态',
  `up_down_status` int DEFAULT '0' COMMENT '上架状态',
  `quantity` int DEFAULT '0' COMMENT '库存',
  `store_id` bigint NOT NULL COMMENT '店铺ID',
  `head_image` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '头图',
  `year_code` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '年份',
  `season_code` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '季节',
  `weight` decimal(20,2) DEFAULT NULL COMMENT '重量',
  `product_info` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT '商品详情',
  `create_time` datetime(6) DEFAULT NULL COMMENT '创建者',
  `create_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '修改者',
  `update_time` datetime(6) DEFAULT NULL COMMENT '修改时间',
  `delete_flag` int DEFAULT NULL COMMENT '删除标志 true/false 删除/未删除',
  `old_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `index_1` (`product_code`,`store_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='商品表';

